// Custom initiative with policyDefinitionGroups for an internal control framework
{
  "policyDefinitionGroups": [
    {
      "name": "CTRL-01",
      "displayName": "CTRL-01: Identity and Access Management",
      "description": "Controls related to user identity verification and access provisioning"
    },
    {
      "name": "CTRL-02",
      "displayName": "CTRL-02: Data Protection",
      "description": "Controls for encryption, data classification, and data handling"
    },
    {
      "name": "CTRL-03",
      "displayName": "CTRL-03: Network Security",
      "description": "Controls for network segmentation, ingress/egress filtering"
    }
  ],
  "policyDefinitions": [
    {
      "policyDefinitionId": "...",
      "policyDefinitionReferenceId": "requireMfa",
      "groupNames": ["CTRL-01"],
      "parameters": { "effect": { "value": "[parameters('mfaEffect')]" } }
    },
    {
      "policyDefinitionId": "...",
      "policyDefinitionReferenceId": "requireCmkStorage",
      "groupNames": ["CTRL-02"],
      "parameters": { "effect": { "value": "[parameters('encryptionEffect')]" } }
    },
    {
      "policyDefinitionId": "...",
      "policyDefinitionReferenceId": "denyPublicStorage",
      "groupNames": ["CTRL-02", "CTRL-03"],
      // Policy maps to two controls — counted in both
      "parameters": { "effect": { "value": "[parameters('storageNetworkEffect')]" } }
    }
  ]
}

# Assign the CIS Microsoft Azure Foundations Benchmark v2.0
# at management group scope via Terraform

variable "log_analytics_workspace_id" {
  type        = string
  description = "Resource ID of the Log Analytics workspace for diagnostic settings"
}

variable "corp_mg_id" {
  type        = string
  description = "Resource ID of the corporate management group"
}

# CIS v2.0 built-in initiative ID (stable)
locals {
  cis_v2_initiative_id = "/providers/Microsoft.Authorization/policySetDefinitions/06f19060-9e68-4070-92ca-f15cc126059e"
}

resource "azurerm_management_group_policy_assignment" "cis_v2" {
  name                 = "cis-v2-benchmark"
  management_group_id  = var.corp_mg_id
  policy_definition_id = local.cis_v2_initiative_id
  display_name         = "CIS Microsoft Azure Foundations Benchmark v2.0"

  parameters = jsonencode({
    logAnalyticsWorkspaceId = {
      value = var.log_analytics_workspace_id
    }
    # Disable checks that do not apply or have compensating controls
    # Parameter names are effect-<policyDefinitionReferenceId>
    # Discover them with: az policy set-definition show --name 06f19060-... | jq '.parameters | keys'
  })
}

# Grant Defender for Cloud access to read compliance data (needed for dashboard)
# Defender for Cloud is auto-provisioned on subscription assignment
# but you must enable Defender plans for full compliance coverage
resource "azurerm_security_center_subscription_pricing" "defender_servers" {
  tier          = "Standard"
  resource_type = "VirtualMachines"
}

# Output the compliance assignment ID for reference
output "cis_assignment_id" {
  value = azurerm_management_group_policy_assignment.cis_v2.id
}
